import React, { useEffect, useRef } from "react";
import type { HistoryRound } from "../types/crash";

function classifyMultiplier(multiplier: string | null): "low" | "mid" | "cyan" | "purple" {
  if (!multiplier) return "low";
  const value = Number(multiplier);
  if (!Number.isFinite(value) || value < 2) return "low";      // red
  if (value <= 5) return "mid";                                // yellow
  if (value < 10) return "cyan";                               // cyan
  return "purple";                                             // purple
}

export function RecentRounds({ rounds }: { rounds: HistoryRound[] }) {
  const listRef = useRef<HTMLUListElement | null>(null);
  useEffect(() => {
    const el = listRef.current;
    if (!el) return;
    el.scrollLeft = el.scrollWidth;
  }, [rounds]);
  return (
    <ul data-testid="history-list" className="chips" ref={listRef}>
      {rounds.map((round) => (
        <li key={round.roundId} className={`chip ${classifyMultiplier(round.crashMultiplier)}`}>
          {round.crashMultiplier ?? "n/a"}x
        </li>
      ))}
    </ul>
  );
}
